import { NavLink } from "react-router-dom";
import Icon from "./Icon";
import StatusBadge from "./StatusBadge";

const NAV_ITEMS = [
  { to: "/overview", label: "Overview", icon: "dashboard" },
  { to: "/monitoring", label: "Live Monitoring", icon: "monitor" },
  { to: "/patients", label: "Patients", icon: "patients" },
  { to: "/history", label: "Patient History", icon: "history" },
  { to: "/alerts", label: "Alerts", icon: "alerts" },
  { to: "/devices", label: "Device Status", icon: "devices" },
  { to: "/reports", label: "Reports", icon: "reports" },
  { to: "/settings", label: "Settings", icon: "settings" },
];

export default function SidebarNav() {
  return (
    <aside className="vp-sidebar">
      <div className="vp-brand">
        <div className="vp-brand-mark">VP</div>
        <div>
          <strong>VitalPulse</strong>
          <span>Zimbabwe Rural Care</span>
        </div>
      </div>
      <nav className="vp-nav">
        {NAV_ITEMS.map((item) => (
          <NavLink
            key={item.to}
            to={item.to}
            className={({ isActive }) => `vp-nav-item ${isActive ? "is-active" : ""}`}
          >
            <Icon name={item.icon} size={18} />
            <span>{item.label}</span>
          </NavLink>
        ))}
      </nav>
      <div className="vp-sidebar-panel">
        <div className="vp-ai-chip">
          <Icon name="spark" size={14} />
          <span>Clinical AI</span>
        </div>
        <h4>Insight workflow</h4>
        <p>AI summaries, anomaly explanations, and report assistance are scaffolded and ready for backend enablement.</p>
        <StatusBadge value="Pending" />
      </div>
      <p className="vp-sidebar-meta">Version 1.0 | Clinical Ops Role</p>
    </aside>
  );
}
